window.__QUIZ_DATA__=[{"id":"theory>Physics>2019>1","subject":"Physics","year":"2019","type":"Theory","sub_label":"1","group":"","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"A stone of mass 20g is released from a catapult whose rubber is stretched through 5cm. If the force constant of the rubber is 200Nm-1, calculate the speed with which the stone leaves the catapult.","images":[],"marking_scheme":"Work done by elastic material = The kinetic energy of the moving stone  1/2Ke2 = 1/2MV2  e=5cm\u00d71m100=0.05m  mass=20g\u00d7kg1000=0.02kg  substituting   1/2 x 200\u00d7(0.05)2=12\u00d70.02\u00d7V2  0.5 = 0.02 \u00d7 V2  V2 = 25  V = &radic;25&nbsp; = 5m/s","marks":"3","difficulty":"2"},{"id":"theory>Physics>2019>2>a","subject":"Physics","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PROJECTILE MOTION :","question":"The diagram above illustrates a projectile motion. Identify each of the physical quantities labelled P, \u03b2, H and R.","images":["data:image/png;base64,"],"marking_scheme":"Height (H) \u21d2 Maximum vertical Height attained by the projectile.    P- is the initial velocity of the projectile    R - is the total horizontal distance covered by the projectile during flight.    \u03b2 - Initial angle the projectile is launched to the horizontal plane.","marks":"2","difficulty":"3"},{"id":"theory>Physics>2019>2>b","subject":"Physics","year":"2019","type":"Theory","sub_label":"b","group":"","topic":"PROJECTILE MOTION :","question":"Write an equation to show the relationship between P, g and Rmax, where g is the acceleration due to gravity and Rmax is maximum R.","images":["data:image/png;base64,"],"marking_scheme":"R=P2sin(2\u03b2)g  when R is maximum, \u03b2 = 45  Rmax=P2g","marks":"1","difficulty":"3"},{"id":"theory>Physics>2019>3","subject":"Physics","year":"2019","type":"Theory","sub_label":"3","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"State three observable phenomena in which waves behave like a particle.","images":[],"marking_scheme":"i. Photo-electric effect - when ultraviolet shines on some metals and photoelectrons are emitted. The light is acting as a particle.  ii. Thermonic equation.  iii. Compton effect.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2019>4","subject":"Physics","year":"2019","type":"Theory","sub_label":"4","group":"CLOSENESS","topic":"MAGNETIC FIELD : THE EARTH\u2019S MAGNETIC FIELD","question":"List three magnetic elements that determine the earth's magnetic field at a point.","images":[],"marking_scheme":"- Magnetic Declination.  - Horizontal component of Earth's magnetic field  - The angle of Dip or Magnetic Inclination.","marks":"3","difficulty":"1"},{"id":"theory>Physics>2019>5>a","subject":"Physics","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Explain this term as used in Electronics:  free electrons.","images":[],"marking_scheme":"Free electron are electrons in a material/atom that can contribute to electric current. It is an electron that is free to move under the influence of an applied electric or magnetic field. They are mobile electrons which are free for bonding.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>5>b","subject":"Physics","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Explain this term as used in Electronics:  holes.","images":[],"marking_scheme":"A hole is the absence of an electron in a particular place in an atom.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2019>6>a","subject":"Physics","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"FIBRE OPTICS :","question":"State the principle of operation of fibre optics.","images":[],"marking_scheme":"Principle of operation of fiber optics state that the density of transparent glass and the refractive index is greater than the density of the two mirrors. It makes use of the principle of the total internal reflection.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2019>6>b","subject":"Physics","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"FIBRE OPTICS :","question":"State two applications of fibre optics in medicine.","images":[],"marking_scheme":"1. Surgical and diagnostic instrumentation.  2. To convey information.  3. Light therapy.  4. Dental hand pieces.  5. Illumination.  6. Laser delivery system.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2019>7>a","subject":"Physics","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Define diffusion.","images":[],"marking_scheme":"Diffusion is a process in which matter flows from region of high concentration to a region of low concentration resulting from random motion of molecules.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2019>7>b","subject":"Physics","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"State two factors that affect the rate of diffusion.","images":[],"marking_scheme":"1. Temperature - diffusion rate increase with increase in temperature.  2. Density.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2019>8>a>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"GRAVITATIONAL FIELD : NEWTON\u2019S LAW OF GRAVITATION","question":"State Newton's Law of Universal Gravitation.","images":[],"marking_scheme":"Newton's law of universal gravitation states that every particle attracts every other particle in the universe with a force which is directly proportional to the product of their masses and inversely proportional to distance between their centres.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>8>a>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"GRAVITATIONAL FIELD : CONCEPT OF GRAVITATIONAL FIELD","question":"Define gravitational field.","images":[],"marking_scheme":"Gravitational field is the region of space surrounding a body in which another body experiences the gravitational force of the body","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>8>b>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"Derive the equation relating the universal gravitational constant, G, and the acceleration of free fall, g, at the surface of the earth from Newton's law of universal gravitation.","images":[],"marking_scheme":"From newton's law of universal gravitation  F=GMeMre2  Where Me is mass of the earth  M is any mass on the earth  re is the distance of mass from centre of the earth.  G is the gravitational constant  But F = mg,  Therefore,  mg=GMeMre2  g=GMere2","marks":"4","difficulty":"3"},{"id":"theory>Physics>2019>8>b>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"State two assumptions for which the relationship in 8(b)(i) holds.","images":[],"marking_scheme":"- That \"g\" depends on the earth alone.  - That the earth is a sphere.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2019>8>c","subject":"Physics","year":"2019","type":"Theory","sub_label":"c","group":"","topic":"GRAVITATIONAL FIELD : NEWTON\u2019S LAW OF GRAVITATION","question":"Calculate the force of attraction between a star of mass 2.00 \u00d7 1030 kg and the earth assuming the star is located 1.50 \u00d7 108km from the earth.  [Mass of the earth = 5.98 \u00d7 1024kg, G = 6.67 \u00d7 10-11Nm2kg-2, g = 10ms-2]","images":[],"marking_scheme":"UsingF=GMeMr2  substituting,  F=6.67 \u00d7 10-11 \u00d7 5.98 \u00d7 1024 \u00d7 2 \u00d7 1030(1.5 \u00d7 108)2 = 3.5455 \u00d7 1028N","marks":"4","difficulty":"3"},{"id":"theory>Physics>2019>8>d>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"GRAVITATIONAL FIELD : GRAVITATIONAL POTENTIAL AND ESCAPE VELOCITY","question":"Define escape velocity.","images":[],"marking_scheme":"Escape velocity is the minimum velocity required for an object to escape or leave the gravitational influence or field of a body.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>8>d>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"State two differences between the acceleration of free fall (g) and the universal gravitational constant (G).","images":[],"marking_scheme":"- g varies across the earth, but G is constant.  - The unit of g is m/s2while G is Nm2/kg2","marks":"4","difficulty":"2"},{"id":"theory>Physics>2019>9>a>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"HEAT ENERGY : LATENT HEAT","question":"Explain latent heat.","images":[],"marking_scheme":"Latent heat is the energy absorbed or released by a body/substance during change in its physical state. The latent heat of fusion is associated with melting of a solid or freezing of a liquid. Latent heat of vaporization is the vaporizing of a liquid or solid. Latent heat is expressed Joules per kilogram.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>9>a>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"HEAT ENERGY : EVAPORATION AND BOILING","question":"State two factors that affect the rate of evaporation of a liquid.","images":[],"marking_scheme":"- Surface area in contact with the atmospheric  - Temperature  - Density  - Wind velocity.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>9>b>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"Explain this observation:  On a dry day, water in a clay pot is cooler than water in a closed plastic container.","images":[],"marking_scheme":"The walls of a clay pot are porous, these leads to seepage which gets evaporated, heat is lost in the process of evaporation making the water, cooler. A closed plastic experiences no evaporation to the the atmosphere and no heat is given out.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>9>b>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT TRANSFER","question":"Explain this observation:  Food gets cooked faster in a pressure cooker than in an ordinary cooking pot.","images":[],"marking_scheme":"An increase in pressure in the cooker increase the ambient temperature in the cooker hence the food cooks faster.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2019>9>c","subject":"Physics","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"State two effects of heat on a substance.","images":[],"marking_scheme":"- Change in temperature.  - Change in state of a substance.  - Increase in volume.","marks":"4","difficulty":"1"},{"id":"theory>Physics>2019>9>d>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF FUSION","question":"A 40V electric heater is used to supply a current of 12A for 1400s to a body of mass 1.5kg at the melting point of the body. The body melts and its temperature rises through 60\u00b0C in an extra 72s. Determine the latent heat of fusion of the body.","images":[],"marking_scheme":"Heat supplied = IVt  \u21d2 12 \u00d7 40 \u00d7 4000  \u21d2 672,000J  Heat supplied = mass \u00d7 latent heat of fusion (l)    672,000 = 1.5l  l=672,0001.5=4.48\u00d7105jkg-1","marks":"6","difficulty":"3"},{"id":"theory>Physics>2019>9>d>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"FINAL","topic":"HEAT ENERGY : SPECIFIC HEAT CAPACITY","question":"A 40V electric heater is used to supply a current of 12A for 1400s to a body of mass 1.5kg at the melting point of the body. The body melts and its temperature rises through 60\u00b0C in an extra 72s. Determine the specific heat capacity of the body.","images":[],"marking_scheme":"IVt = MC\u03b8  where, M is mass  C is specific heat capacity of the body  \u03b8 is temperature change  \u03b8 = 60\u00b0C, M = 1.5kg, C = ?, t = 75 seconds  substituting  40 \u00d7 12 \u00d7 72 = 1.5 \u00d7 60 \u00d7 C  C=36,0001.5 \u00d7 60 = 384J/kg/k","marks":"4","difficulty":"3"},{"id":"theory>Physics>2019>10>a>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Define atomic spectra.","images":[],"marking_scheme":"Atomic spectra is the spectrum of frequencies of electromagnetic radiation emitted or absorbed during transitions of electrons between energy levels within an atom.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2019>10>a>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"Differentiate between emission spectra and absorption spectra.","images":[],"marking_scheme":"Absorption lines are where light has been absorbed by the atom, while emission spectra have spikes in the spectra due to atoms releasing photons at those wavelength.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2019>10>b>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The diagram above illustrates an electron transition from energy level n = 3 to n = 1.  Calculate the energy of the photon.  [h = 6.6 \u00d7 10-34Js, c = 3.0 \u00d7 108ms-1, 1eV = 1.6 \u00d7 10-19J]","images":["data:image/png;base64,"],"marking_scheme":"The electron falls from n = 3 level to n = 1 level   Final level - Initial level  -13.6eV - (-1.51eV)  \u21d2 -12.09eV  1eV = 1.6 \u00d7 10-19J  Energy of the photon = -12.09 \u00d7 1.6 \u00d7 10-19J  \u21d2 -19.344 \u00d7 10-19J  (The sign indicates energy was released).","marks":"4","difficulty":"3"},{"id":"theory>Physics>2019>10>b>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The diagram above illustrates an electron transition from energy level n = 3 to n = 1.  Calculate the frequency of the photon.  [h = 6.6 \u00d7 10-34Js, c = 3.0 \u00d7 108ms-1, 1eV = 1.6 \u00d7 10-19J]","images":["data:image/png;base64,"],"marking_scheme":"E = hv  Where h = 6.6 \u00d7 10-34  v = frequency  v=Eh  substituting,  v=19.344 \u00d7 10-196.6 \u00d7 10-34  \u21d2 2.9 \u00d7 1015hz.  Frequency = 2.9 \u00d7 1015Hz","marks":"4","difficulty":"3"},{"id":"theory>Physics>2019>10>b>iii","subject":"Physics","year":"2019","type":"Theory","sub_label":"iii","group":"","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The diagram above illustrates an electron transition from energy level n = 3 to n = 1.  Calculate the wavelength of the photon.  [h = 6.6 \u00d7 10-34Js, c = 3.0 \u00d7 108ms-1, 1eV = 1.6 \u00d7 10-19J]","images":["data:image/png;base64,"],"marking_scheme":"C = \u03bbF  \u03bb=CF  substituting for C = 3 \u00d7 108ms-1 and F = 2.9 \u00d7 1015  \u03bb=3 \u00d7 1082.9 \u00d7 1015  \u21d2 1.034 \u00d7 10-7m  Wavelength of the photon is 1.034 \u00d7 10-7m","marks":"4","difficulty":"3"},{"id":"theory>Physics>2019>10>c>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"Differentiate between soft x-rays and hard x-rays.","images":[],"marking_scheme":"- Hard X-rays have short wavelength while soft x-rays have relatively longer wavelength.  - Hard X-rays are more penetrating than soft X-rays.  - Hard X-rays are the high energy X-rays while soft X-rays are low energy X-rays.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2019>10>c>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Draw the circuit symbol for a p - n junction diode.","images":["data:image/png;base64,"],"marking_scheme":"Circuit symbol for a p-n junction diode.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>10>c>iii","subject":"Physics","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ELECTRICAL CONDUCTION THROUGH MATERIALS [ELECTRONIC] :","question":"Give the reason for doping a semiconductor material.","images":[],"marking_scheme":"Doping is done to change the conductivity of the semiconducting devices, where it creates an extra hole or provides an extra electron(s) depending on the dopant used.  Also to produce more junctions.","marks":"1","difficulty":"2"},{"id":"theory>Physics>2019>11>a>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MOTION : TYPES OF FORCE","question":"Define force and state its S. I. unit.","images":[],"marking_scheme":"Force is push or pull on an object. Force is anything that causes motion. Newton(N) or Kgm/s2","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>11>a>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MOTION : SOLID FRICTION","question":"List the two types of solid friction.","images":[],"marking_scheme":"- Static friction  - Dynamic friction","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>11>b>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"SPEED AND VELOCITY : VELOCITY-TIME GRAPH","question":"A car travelling at a constant speed of 30 ms-1 for 20s was suddenly decelerated when the driver sighted a pot-hole. It took the driver 6s to get to the pot-hole with a reduced speed of 18ms-1. He maintained the steady speed for another 10s to cross the pot-hole. The brakes were then applied and the car came to rest 5s later.  Draw the velocity-time graph for the journey.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"6","difficulty":"2"},{"id":"theory>Physics>2019>11>b>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"FINAL","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"A car travelling at a constant speed of 30 ms-1 for 20s was suddenly decelerated when the driver sighted a pot-hole. It took the driver 6s to get to the pot-hole with a reduced speed of 18ms-1. He maintained the steady speed for another 10s to cross the pot-hole. The brakes were then applied and the car came to rest 5s later.  Calculate the deceleration during the last 5s of the journey.","images":[],"marking_scheme":"During the 5 seconds part of the journey, it goes from = 18m/s to zero  deceleration=18 - 05=3.6ms2","marks":"4","difficulty":"2"},{"id":"theory>Physics>2019>11>b>iii","subject":"Physics","year":"2019","type":"Theory","sub_label":"iii","group":"FINAL","topic":"MOTION : CAUSE OF MOTION","question":"A car travelling at a constant speed of 30 ms-1 for 20s was suddenly decelerated when the driver sighted a pot-hole. It took the driver 6s to get to the pot-hole with a reduced speed of 18ms-1. He maintained the steady speed for another 10s to cross the pot-hole. The brakes were then applied and the car came to rest 5s later.  Calculate the total distance covered.","images":[],"marking_scheme":"This is gotten by finding the total area of the graph =(30 \u00d7 20) + 1/2 (18 + 30)6 + 18 \u00d7 10 + 1/2 (5 \u00d7 18)  \u21d2 600 + 144 + 180 + 45  \u21d2 969metres","marks":"6","difficulty":"3"},{"id":"theory>Physics>2019>12>a>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above illustrates a structure of a typical photocell.    Identify each of the parts labelled A and B.","images":["data:image/png;base64,"],"marking_scheme":"A \u2192 This is the emittor is shaped in the form of a semi-hollow cylinder. It is of a negative potential.    B \u2192 This is the collector, it is in the shape of a rod, it is of a positive potential.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>12>a>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above illustrates a structure of a typical photocell.  State one functions each of A and B.","images":["data:image/png;base64,"],"marking_scheme":"The emitter (A) emits photoelectrons which is attracted towards the collector.  The collector(B) is the output, it attracts the photoelectrons released by the emitter.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>12>a>iii","subject":"Physics","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"The diagram above illustrates a structure of a typical photocell.  Einstein's photoelectric equation can be written as E = hf - Wo. State what each of the terms E, hf and Wo represents.","images":["data:image/png;base64,"],"marking_scheme":"E = Energy of photoelectron (maximum kinetic energy)  hf = Energy of light used  Wo = work function - work of pull away electron.","marks":"3","difficulty":"2"},{"id":"theory>Physics>2019>12>b","subject":"Physics","year":"2019","type":"Theory","sub_label":"b","group":"","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"A photon is incident on a metal whose work function is 1.32eV. An electron is emitted from the surface with a maximum kinetic energy of 1.97 eV. Calculate the frequency of the photon.  [1 eV = 1.6 \u00d7 10-19J]","images":[],"marking_scheme":"E = hf - Wo  Therefore, hf = E + Wo  hf = 1.32 + 1.97 = 3.29eV  F=3.29eVh  F=3.29 \u00d7 1.6 \u00d7 10-196.6 \u00d7 10-34 = 7.976 \u00d7 1014Hz","marks":"7","difficulty":"3"},{"id":"theory>Physics>2019>12>c>i","subject":"Physics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Define half-life of a radioactive element.","images":[],"marking_scheme":"Half-life of a radioactive element is the time it takes for half of the original isotope to decay.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2019>12>c>ii","subject":"Physics","year":"2019","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Sketch a graph of the relation N = Noe-\u03bbt and indicate the half-life.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"}];